# Definition for a binary tree node.
class TreeNode:
    def __init__(self, x):
        self.val = x
        self.left = None
        self.right = None

class Solution:
    def isSameTree(self, p: TreeNode, q: TreeNode) -> bool:
        # Base case: if both trees are empty, they are the same
        if not p and not q:
            return True

        # If one tree is empty and the other is not, they are not the same
        if not p or not q:
            return False

        # If the values of the current nodes are different, the trees are not the same
        if p.val != q.val:
            return False

        # Recursively check the left and right subtrees
        return self.isSameTree(p.left, q.left) and self.isSameTree(p.right, q.right)

# Time Complexity: O(n)
# Space Complexity: O(n)
# Algorithm: Recursive depth-first search to compare the structure and values of two binary trees
